package controllers

import javax.inject._
import play.api.mvc._
import play.api.db.slick._
import slick.driver.JdbcProfile
import models.Product

@Singleton
class ProductController @Inject()(cc: ControllerComponents, dbConfigProvider: DatabaseConfigProvider) extends AbstractController(cc) {
  // Get a database config and create a Slick session
  val dbConfig = dbConfigProvider.get[JdbcProfile]
  val db = dbConfig.db

  def searchProducts() = Action { implicit request =>
    // Get search parameters from request.queryString
    val q = request.queryString("q")
    val categoryId = request.queryString("category_id")

    // Build dynamic WHERE clause using string interpolation
    val sqlFragment = s"(name LIKE '%$q%' OR description LIKE '%$q%') AND (${if (categoryId == "") "1=1" else s"category_id=$categoryId"})"

    // Execute raw SQL query with the WHERE clause
    db.run(sql"SELECT * FROM products WHERE ${sqlFragment}".as[Product])
  }
}